	private static void writeRecords(Path file, Schema schema, List<GenericRecord> records) throws Exception {
		try (ParquetWriter<GenericRecord> writer = AvroParquetWriter.<GenericRecord>builder(new LocalOutputFile(file))
				.withSchema(schema)
				.withCompressionCodec(CompressionCodecName.UNCOMPRESSED)
				.build()) {
			for (GenericRecord record : records) {
				writer.write(record);
			}
		}
	}

	private static GenericRecord record(Schema schema, Object... values) {
		GenericRecord record = new GenericData.Record(schema);
		for (int i = 0; i < values.length; i += 2) {
			record.put((String) values[i], values[i + 1]);
		}
		return record;
	}

	private static void writeMappingFile(Path mappingFile, Path peopleFile, Path citiesFile, String graph)
			throws Exception {
		ObjectNode root = OBJECT_MAPPER.createObjectNode();
		root.putObject("prefixes")
				.put("ex", "http://example.com/")
				.put("rdf", "http://www.w3.org/1999/02/22-rdf-syntax-ns#");

		ArrayNode sources = root.putArray("sources");
		sources.addObject()
				.put("id", "people")
				.putArray("paths")
				.add(peopleFile.toString());
		sources.addObject()
				.put("id", "cities")
				.putArray("paths")
				.add(citiesFile.toString());

		ObjectNode mapping = root.putArray("mappings").addObject();
		mapping.put("id", "people-mapping");
		mapping.putObject("from")
				.put("source", "people")
				.put("alias", "p");
		if (graph != null) {
			mapping.put("graph", graph);
		}
		mapping.putObject("subject")
				.put("termType", "iri")
				.put("template", "ex:person/{p.id}");
		mapping.putArray("joins")
				.addObject()
				.put("source", "cities")
				.put("alias", "c")
				.putArray("on")
				.addObject()
				.put("left", "p.city_id")
				.put("right", "c.id");

		ArrayNode triples = mapping.putArray("triples");
		triples.addObject()
				.put("predicate", "rdf:type")
				.putObject("object")
				.put("termType", "iri")
				.put("value", "ex:Person");
		triples.addObject()
				.put("predicate", "ex:name")
				.putObject("object")
				.put("termType", "literal")
				.put("column", "p.name");
		triples.addObject()
				.put("predicate", "ex:cityName")
				.putObject("object")
				.put("termType", "literal")
				.put("column", "c.label");

		Files.writeString(mappingFile, OBJECT_MAPPER.writerWithDefaultPrettyPrinter().writeValueAsString(root));
	}

	private static Object invokeDeclared(Object target, String methodName, Object... args) throws Exception {
		Method method = target.getClass().getDeclaredMethod(methodName, parameterTypes(args));
		method.setAccessible(true);
		return method.invoke(target, args);
	}

	private static long invokeLong(Object target, String methodName, Object... args) throws Exception {
		return ((Number) invokeDeclared(target, methodName, args)).longValue();
	}

	private static Class<?>[] parameterTypes(Object[] args) {
		Class<?>[] parameterTypes = new Class<?>[args.length];
		for (int i = 0; i < args.length; i++) {
			parameterTypes[i] = args[i].getClass();
		}
		return parameterTypes;
	}
